def calc_kama(c,n,fast,slow):
    f=2/(fast+1);s=2/(slow+1);k=[None]*len(c)
    if len(c)<=n: return k
    k[n]=c[n]
    for i in range(n+1,len(c)):
        d=abs(c[i]-c[i-n]);v=sum(abs(c[j]-c[j-1]) for j in range(i-n+1,i+1))
        er=d/v if v else 0;sc=(er*(f-s)+s)**2;k[i]=k[i-1]+sc*(c[i]-k[i-1])
    return k

def calc_sar(h,l,step,maf):
    n=len(h);sar=[None]*n
    if n<5: return sar
    bull=h[1]>h[0];af=step;ep=max(h[:2]) if bull else min(l[:2])
    sar[1]=min(l[:2]) if bull else max(h[:2])
    for i in range(2,n):
        ps=sar[i-1]
        if bull:
            sar[i]=min(ps+af*(ep-ps),l[i-1],l[i-2] if i>=2 else l[i-1])
            if l[i]<sar[i]: bull=False;af=step;sar[i]=ep;ep=l[i]
            elif h[i]>ep: ep=h[i];af=min(af+step,maf)
        else:
            sar[i]=max(ps+af*(ep-ps),h[i-1],h[i-2] if i>=2 else h[i-1])
            if h[i]>sar[i]: bull=True;af=step;sar[i]=ep;ep=h[i]
            elif l[i]<ep: ep=l[i];af=min(af+step,maf)
    return sar

def calc_ao(h,l,fa,sl):
    mid=[(a+b)/2 for a,b in zip(h,l)]
    if len(mid)<sl: return 0
    def ema(a,p):
        k=2/(p+1);e=a[0]
        for x in a[1:]: e=x*k+e*(1-k)
        return e
    return round(ema(mid,fa)-ema(mid,sl),4)

def calc_er(c,n=10):
    if len(c)<n+1: return 0
    d=abs(c[-1]-c[-n-1]);v=sum(abs(c[-i]-c[-i-1]) for i in range(1,n+1))
    return round(d/v,4) if v else 0

def calc_rsi(c,n=14):
    if len(c)<n+2: return 50
    g,lo=[],[]
    for i in range(1,len(c)):
        d=c[i]-c[i-1];g.append(max(d,0));lo.append(max(-d,0))
    ag=sum(g[-n:])/n;al=sum(lo[-n:])/n
    return round(100-100/(1+ag/al),2) if al else 100

def calc_baf(h,l,fa,sl):
    mid=[(a+b)/2 for a,b in zip(h,l)]
    if len(mid)<sl: return 0
    def ema(a,p):
        k=2/(p+1);e=a[0]
        for x in a[1:]: e=x*k+e*(1-k)
        return e
    ao_s=[ema(mid[:i+1],fa)-ema(mid[:i+1],sl) for i in range(len(mid))]
    n=0
    for i in range(len(ao_s)-1,0,-1):
        if ao_s[i]>ao_s[i-1]: n+=1
        else: break
    return n

def calc_vol_r(vol):
    if len(vol)<21: return 1.0
    avg=sum(vol[-21:-1])/20
    return round(vol[-1]/avg,2) if avg>0 else 1.0

def get_zona(p,kf,ks):
    if not kf or not ks: return 'ND'
    if p>kf and kf>ks: return 'LONG_CONF'
    if p>kf and p>ks: return 'LONG_EARLY'
    if p<ks:
        gap=(ks-p)/ks*100 if ks>0 else 0
        return 'STOP' if gap>2 else 'USCITA'
    return 'GRIGIA'

def get_seg(zona,ao,vol,er,baf,kf,ks,sb,reg,p):
    if reg in ('STRESS','PAURA'):
        return 'STOP' if zona=='STOP' else 'USCITA' if zona=='USCITA' else ''
    gap_ok=abs(kf-ks)/ks>=0.003 if kf and ks and ks>0 else True
    if zona=='LONG_CONF' and ao>0 and vol>=p['vm'] and baf>=p['bm'] and er>=p['em'] and gap_ok and sb:
        return 'LONG'
    if zona=='LONG_EARLY' and ao>0 and baf>=p['bm'] and gap_ok and reg!='ATTENZIONE':
        return 'EARLY'
    if zona in ('LONG_CONF','LONG_EARLY'): return 'WATCH'
    if zona=='STOP': return 'STOP'
    if zona=='USCITA': return 'USCITA'
    if zona=='GRIGIA': return 'ATTENZIONE'
    return ''

def get_score(zona,ao,vol,er,baf,sb,mult):
    b=0
    if zona=='LONG_CONF': b=60
    elif zona=='LONG_EARLY': b=40
    elif zona=='GRIGIA': b=20
    b+=min(baf,5)*6+(10 if ao>0 else 0)+min(vol,3)*4+er*20+(8 if sb else 0)
    return round(b*mult,1)

def get_entry_date(close,kf_arr,ks_arr,ts):
    try:
        zs=[]
        for i in range(len(close)):
            kf=kf_arr[i];ks=ks_arr[i]
            zs.append(get_zona(close[i],kf,ks) if kf and ks else 'ND')
        cur=zs[-1]
        for idx in range(len(zs)-2,max(0,len(zs)-60),-1):
            if zs[idx]!=cur:
                dt=datetime.datetime.fromtimestamp(ts[idx+1])
                return dt.strftime('%d/%m %H:%M')
    except: pass
    return '—'

def fetch_vix():
    vix=None;vs=None
    for sym,k in [('^VIX','v'),('^V2TX','vs')]:
        try:
            h=yf.Ticker(sym).history(period='5d',interval='1d',timeout=10)
            if not h.empty:
                val=round(float(h['Close'].iloc[-1]),2)
                if k=='v': vix=val
                else: vs=val
        except: pass
        time.sleep(0.3)
    avg=((vix or 20)+(vs or 20))/2
    if avg<15:   r,m,c='CALMA',1.00,'verde'
    elif avg<20: r,m,c='NORMALE',0.95,'giallo'
    elif avg<25: r,m,c='ATTENZIONE',0.85,'arancio'
    elif avg<28: r,m,c='STRESS',0.70,'rosso'
    else:        r,m,c='PAURA',0.50,'rosso_scuro'
    return {'vix':vix,'vstoxx':vs,'regime':r,'mult':m,'color':c}

def process(info,mult,reg_name):
    tipo=info.get('tipo','ULTRA');p=PARAMS.get(tipo,PARAMS['ULTRA'])
    sym=info['y']
    try:
        tk=yf.Ticker(sym);hist=tk.history(period='1y',interval='1d',timeout=15)
        if hist.empty or len(hist)<40: return None
        nome=info.get('n','')
        if not nome:
            try:
                meta=tk.fast_info;nome=getattr(meta,'long_name','') or getattr(meta,'short_name','') or '';nome=nome[:60]
            except: nome=''
        c=[float(x) for x in hist['Close'].values]
        h=[float(x) for x in hist['High'].values]
        l=[float(x) for x in hist['Low'].values]
        v=[float(x) for x in hist['Volume'].values]
        ts=[int(t.timestamp()) for t in hist.index]
        kfa=calc_kama(c,*p['kf']);ksa=calc_kama(c,*p['ks'])
        sa=calc_sar(h,l,p['ss'],p['sm'])
        kf=kfa[-1];ks=ksa[-1];sv=sa[-1];lc=c[-1]
        sb=sv is not None and lc>sv
        ao=calc_ao(h,l,p['af'],p['as_']);er=calc_er(c);rsi=calc_rsi(c)
        baf=calc_baf(h,l,p['af'],p['as_']);vr=calc_vol_r(v)
        zona=get_zona(lc,kf,ks);seg=get_seg(zona,ao,vr,er,baf,kf,ks,sb,reg_name,p)
        score=get_score(zona,ao,vr,er,baf,sb,mult)
        ed=get_entry_date(c,kfa,ksa,ts)
        p5=round((lc/c[-6]-1)*100,2) if len(c)>6 else 0
        p20=round((lc/c[-21]-1)*100,2) if len(c)>21 else 0
        return {'ticker':info['t'],'yahoo':sym,'nome':nome,'tipo':tipo,'c':info.get('c',''),
                'provider':info.get('provider',''),'zona':zona,'segnale':seg,'score':score,
                'prezzo':round(lc,4),'kama_fast':round(kf,4) if kf else None,
                'kama_slow':round(ks,4) if ks else None,'sar':round(sv,4) if sv else None,
                'sarBull':sb,'er':er,'baff':baf,'ao':round(ao,4),'rsi':rsi,
                'volRatio':vr,'perfSett':p5,'perfMese':p20,'entryDate':ed,
                'quality':seg in ('LONG','EARLY')}
    except: return None

def send_email(alerts,vix,vstoxx,regime,now,prev_regime=None):
    import smtplib,os
    from email.mime.multipart import MIMEMultipart
    from email.mime.text import MIMEText
    EU=os.environ.get('EMAIL_USER','');EP=os.environ.get('EMAIL_PASS','')
    if not EU or not EP: print("EMAIL skip");return
    ICONS={'LONG_CONF':'🟢 LONG CONF','LONG_EARLY':'🔵 LONG EARLY','GRIGIA':'🟡 GRIGIA','USCITA':'🔴 USCITA','STOP':'⛔ STOP'}
    TIPO={'ULTRA':'💼','SETTORIALI':'🏭','TEMATICI':'🚀','COMMODITIES':'🌾'}
    subj=("⚠️ REGIME {} → " if prev_regime else "🦅 RAPTOR TWO — ").format(regime if prev_regime else '')+"{}  segnale/i · {}".format(len(alerts),now.strftime('%d/%m/%Y %H:%M'))
    rows=""
    for a in alerts:
        bg='#dafbe1' if 'LONG' in a['new'] else '#ffebe9'
        rows+='<tr style="background:{}"><td style="padding:6px;font-weight:700">{}</td><td style="padding:6px">{}</td><td style="padding:6px;font-size:10px;color:#57606a">{}</td><td style="padding:6px">{}</td><td>→</td><td style="padding:6px;font-weight:700">{}</td><td style="padding:6px;font-family:monospace">{}</td><td style="padding:6px;font-weight:700">{}</td><td style="padding:6px">{}</td></tr>'.format(
            bg,a['ticker'],TIPO.get(a.get('tipo',''),''),
            (a['nome'] or '')[:40],ICONS.get(a['old'],a['old']),
            ICONS.get(a['new'],a['new']),a['prezzo'],a['score'],a['entry'])
    html='<!DOCTYPE html><html><body style="font-family:sans-serif;background:#f5f7fa;padding:20px"><div style="max-width:860px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden"><div style="background:#1f2328;color:#fff;padding:14px 20px"><h2 style="margin:0">🦅 RAPTOR TWO — Nuovi Segnali</h2><p style="margin:4px 0 0;font-size:12px;opacity:.8">{} · Regime: {} · VIX: {}</p></div><div style="padding:16px"><table style="width:100%;border-collapse:collapse;font-size:12px"><thead><tr style="background:#f5f7fa"><th style="padding:6px;text-align:left">Ticker</th><th>Tipo</th><th style="text-align:left">Nome</th><th>Da</th><th></th><th>A</th><th>Prezzo</th><th>Score</th><th>Data</th></tr></thead><tbody>{}</tbody></table><p style="margin-top:12px;font-size:11px;color:#57606a">📊 <a href="https://giorgiogoldoni.github.io/raptor-two/">RAPTOR Two</a></p></div></div></body></html>'.format(
        now.strftime('%d/%m/%Y %H:%M'),regime,vix,rows)
    try:
        msg=MIMEMultipart('alternative');msg['Subject']=subj;msg['From']=EU;msg['To']=EU
        msg.attach(MIMEText(html,'html'))
        with smtplib.SMTP_SSL('smtp.gmail.com',465) as srv:
            srv.login(EU,EP);srv.sendmail(EU,EU,msg.as_string())
        print("Email: {} alert".format(len(alerts)))
    except Exception as e: print("Email err:",e)

def main():
    now=datetime.datetime.now()
    print("RAPTOR Two Fetch —",now.strftime('%Y-%m-%d %H:%M'))
    print("Ticker:",len(TICKERS))
    reg=fetch_vix()
    print("  VIX={} VSTOXX={} Regime={} mult={}".format(reg['vix'],reg['vstoxx'],reg['regime'],reg['mult']))
    results=[]; errors=0
    for i,info in enumerate(TICKERS):
        r=process(info,reg['mult'],reg['regime'])
        if r: results.append(r)
        else: errors+=1
        if (i+1)%50==0: print("  {}/{} ok:{} err:{}".format(i+1,len(TICKERS),len(results),errors))
        time.sleep(0.3)
    prev_zones={}; prev_reg=''
    try:
        with open('raptor_two.json','r',encoding='utf-8') as f:
            pj=json.load(f)
            for r in pj.get('data',[]): prev_zones[r['ticker']]=r.get('zona','')
            prev_reg=pj.get('regime','')
    except: pass
    reg_changed=prev_reg and prev_reg!=reg['regime']
    CAMBI={('USCITA','LONG_CONF'),('STOP','LONG_CONF'),('GRIGIA','LONG_CONF'),('LONG_EARLY','LONG_CONF'),
           ('USCITA','LONG_EARLY'),('STOP','LONG_EARLY'),('GRIGIA','LONG_EARLY'),
           ('LONG_CONF','USCITA'),('LONG_EARLY','USCITA'),('LONG_CONF','STOP'),('LONG_EARLY','STOP')}
    alerts=[]
    for r in results:
        oz=prev_zones.get(r['ticker'],''); nz=r.get('zona','')
        if r.get('quality') and oz and nz and oz!=nz and (oz,nz) in CAMBI and r.get('score',0)>=55:
            alerts.append({'ticker':r['ticker'],'nome':r.get('nome',''),'tipo':r.get('tipo',''),
                'old':oz,'new':nz,'score':r['score'],'prezzo':r['prezzo'],'entry':r.get('entryDate','—')})
    print("Alert:",len(alerts))
    if alerts or reg_changed:
        send_email(alerts,reg['vix'],reg['vstoxx'],reg['regime'],now,prev_reg if reg_changed else None)
    output={'timestamp':now.isoformat(),'timestamp_it':now.strftime('%d/%m/%Y %H:%M'),
            'total':len(TICKERS),'ok':len(results),'errors':errors,
            'vix':reg['vix'],'vstoxx':reg['vstoxx'],'regime':reg['regime'],
            'regime_mult':reg['mult'],'regime_color':reg['color'],'data':results}
    with open('raptor_two.json','w',encoding='utf-8') as f:
        json.dump(output,f,ensure_ascii=False,separators=(',',':'))
    print("Salvato raptor_two.json — {} OK {} errori".format(len(results),errors))

if __name__=='__main__':
    main()
